145	    while (write_data.size() > 0) {
146	      uint32_t offset4096 = addr % 4096;
147	      uint32_t remainder4096 = 4096 - offset4096;
148	      uint32_t max_transaction_bytes = std::min(4096u, remainder4096);
149	      uint32_t transaction_bytes = std::min(
150	          static_cast<uint32_t>(write_data.size()), max_transaction_bytes);
151	      absl::Span<const uint8_t> local_data =
152	          write_data.subspan(0, transaction_bytes);
153	
154	      std::shared_ptr<bool> transaction =
155	          slave_write_driver_.WriteTransaction(0, addr, local_data);
156	      while (!(*transaction)) {
