169	      uint32_t offset4096 = addr % 4096;
170	      uint32_t remainder4096 = 4096 - offset4096;
171	      uint32_t max_transaction_bytes = std::min(4096u, remainder4096);
172	      uint32_t bytes_remaining = len - result.size();
173	      uint32_t transaction_bytes = std::min(
174	          static_cast<uint32_t>(bytes_remaining), max_transaction_bytes);
175	
176	      auto transaction =
177	          slave_read_driver_.ReadTransaction(0, addr, transaction_bytes);
178	      while (!(transaction->finished)) {
179	        Step();
180	      }
181	      std::copy(transaction->data.begin(), transaction->data.end(),
182	                std::back_inserter(result));
