28	// A class that wraps and controls a verilator clock signal. Also provides an
29	// observer mechanism
30	class Clock {
31	 public:
32	  // A class that observes changes to the clock signal. The constructor and
33	  // destructor will automatically subscribe/unsubscribe from the clock.
34	  class Observer {
35	   public:
36	    explicit Observer(Clock* clock);
37	    virtual ~Observer();
38	
39	    virtual void OnRisingEdge() {}
40	    virtual void OnFallingEdge() {}
41	
42	   protected:
43	    Clock& clock() { return *clock_; }
44	
45	   private:
46	    Clock* const clock_;
47	  };
48	
49	  template <typename Model>
50	  Clock(VerilatedContext* context, uint8_t* clock, Model* model)
51	      : context_(context),
52	        clock_(clock),
53	        eval_function_([model]() { model->eval(); }) {}
54	  ~Clock() = default;
55	
56	  // Advance the clock on cycle (one positive edge, one negative edge).
57	  void Step();
58	
59	  // Update the simulation. If observers change input signals to the design,
60	  // they should call this function to ensure internal signals get updated.
61	  void Eval();
62	
63	 private:
64	  void AddObserver(Observer* observer);
65	  void RemoveObserver(Observer* observer);
66	
67	  VerilatedContext* const context_;
68	  uint8_t* const clock_;
69	  std::function<void()> eval_function_;
70	  std::vector<Observer*> observers_;
71	};
