73	// Struct representing the data transferred in an AXI4 read/write addr channel.
74	struct AxiAddr {
75	  uint32_t addr_bits_addr;
76	  uint8_t addr_bits_prot;
77	  uint8_t addr_bits_id;
78	  uint8_t addr_bits_len;
79	  uint8_t addr_bits_size;
80	  uint8_t addr_bits_burst;
81	  uint8_t addr_bits_lock;
82	  uint8_t addr_bits_cache;
83	  uint8_t addr_bits_qos;
84	  uint8_t addr_bits_region;
85	
86	  // Create an AxiAddr from a transfer id, starting address and transaction
87	  // length.
88	  static AxiAddr FromIdAddrSize(int id, uint32_t addr, uint32_t byte_length);
89	};
