98	// A driver to control interactions of the write channels in an AXI4 slave.
99	class AxiSlaveWriteDriver : Clock::Observer {
100	 public:
101	  AxiSlaveWriteDriver(
102	      Clock* clock, uint8_t* write_addr_valid, uint32_t* write_addr_bits_addr,
103	      uint8_t* write_addr_bits_prot, uint8_t* write_addr_bits_id,
104	      uint8_t* write_addr_bits_len, uint8_t* write_addr_bits_size,
105	      uint8_t* write_addr_bits_burst, uint8_t* write_addr_bits_lock,
106	      uint8_t* write_addr_bits_cache, uint8_t* write_addr_bits_qos,
107	      uint8_t* write_addr_bits_region, const uint8_t* write_addr_ready,
108	      uint8_t* write_data_valid, VlWide<4>* write_data_bits_data,
109	      uint16_t* write_data_bits_strb, uint8_t* write_data_bits_last,
110	      const uint8_t* write_data_ready, const uint8_t* write_resp_valid,
111	      const uint8_t* write_resp_bits_id, const uint8_t* write_resp_bits_resp,
112	      uint8_t* write_resp_ready)
113	      : Clock::Observer(clock),
114	        write_addr_valid_(write_addr_valid),
115	        write_addr_bits_addr_(write_addr_bits_addr),
116	        write_addr_bits_prot_(write_addr_bits_prot),
117	        write_addr_bits_id_(write_addr_bits_id),
118	        write_addr_bits_len_(write_addr_bits_len),
119	        write_addr_bits_size_(write_addr_bits_size),
120	        write_addr_bits_burst_(write_addr_bits_burst),
121	        write_addr_bits_lock_(write_addr_bits_lock),
122	        write_addr_bits_cache_(write_addr_bits_cache),
123	        write_addr_bits_qos_(write_addr_bits_qos),
124	        write_addr_bits_region_(write_addr_bits_region),
125	        write_addr_ready_(write_addr_ready),
126	        write_data_valid_(write_data_valid),
127	        write_data_bits_data_(write_data_bits_data),
128	        write_data_bits_strb_(write_data_bits_strb),
129	        write_data_bits_last_(write_data_bits_last),
130	        write_data_ready_(write_data_ready),
131	        write_resp_valid_(write_resp_valid),
132	        write_resp_bits_id_(write_resp_bits_id),
133	        write_resp_bits_resp_(write_resp_bits_resp),
134	        write_resp_ready_(write_resp_ready) {
135	    // Always ready to accept response
136	    *write_resp_ready_ = 1;
137	  }
138	  ~AxiSlaveWriteDriver() final = default;
139	
140	  std::shared_ptr<bool> WriteTransaction(int id, uint32_t addr,
141	                                         absl::Span<const uint8_t> data) {
142	    // Enqueue addr
143	    AxiAddr axi_addr = AxiAddr::FromIdAddrSize(id, addr, data.size());
144	    EnqueueAddr(axi_addr);
145	
146	    // Enqueue data
147	    while (data.size() > 0) {
148	      uint32_t base_addr = (addr / 16) * 16;
149	      uint32_t sub_addr = addr - base_addr;
150	      uint32_t bytes_to_write = 16 - sub_addr;
151	      bytes_to_write =
152	          std::min(static_cast<uint32_t>(data.size()), bytes_to_write);
153	      absl::Span<const uint8_t> local_data = data.subspan(0, bytes_to_write);
154	
155	      AxiWData axi_data;
156	      uint8_t* data_ptr =
157	          reinterpret_cast<uint8_t*>(&(axi_data.write_data_bits_data[0])) +
158	          sub_addr;
159	      memcpy(data_ptr, local_data.data(), bytes_to_write);
160	      axi_data.write_data_bits_strb = 0;
161	      for (uint32_t i = sub_addr; i < sub_addr + bytes_to_write; i++) {
162	        axi_data.write_data_bits_strb |= (1 << i);
163	      }
164	      axi_data.write_data_bits_last = (bytes_to_write == data.size());
165	      EnqueueData(axi_data);
166	
167	      data.remove_prefix(bytes_to_write);
168	      addr += bytes_to_write;
169	    }
170	
171	    assert(outstanding_transactions_.find(id) ==
172	           outstanding_transactions_.end());
173	
174	    const auto [it, success] =
175	        outstanding_transactions_.insert({id, std::make_shared<bool>(false)});
176	    return it->second;
177	  }
178	
179	 private:
180	  void EnqueueAddr(const AxiAddr& addr) { addr_queue_.push(addr); }
181	
182	  void EnqueueData(const AxiWData& data) { data_queue_.push(data); }
183	
184	  void OnFallingEdge() final {
185	    // Send Addr
186	    *write_addr_valid_ = !addr_queue_.empty();
187	    clock().Eval();
188	    if (!addr_queue_.empty()) {
189	      *write_addr_bits_addr_ = addr_queue_.front().addr_bits_addr;
190	      *write_addr_bits_prot_ = addr_queue_.front().addr_bits_prot;
191	      *write_addr_bits_id_ = addr_queue_.front().addr_bits_id;
192	      *write_addr_bits_len_ = addr_queue_.front().addr_bits_len;
193	      *write_addr_bits_size_ = addr_queue_.front().addr_bits_size;
194	      *write_addr_bits_burst_ = addr_queue_.front().addr_bits_burst;
195	      *write_addr_bits_lock_ = addr_queue_.front().addr_bits_lock;
196	      *write_addr_bits_cache_ = addr_queue_.front().addr_bits_cache;
197	      *write_addr_bits_qos_ = addr_queue_.front().addr_bits_qos;
198	      *write_addr_bits_region_ = addr_queue_.front().addr_bits_region;
199	      if (*write_addr_ready_) {
200	        addr_queue_.pop();
201	      }
202	      clock().Eval();
203	    }
204	
205	    // Send Data
206	    *write_data_valid_ = !data_queue_.empty();
207	    clock().Eval();
208	    if (!data_queue_.empty()) {
209	      *write_data_bits_data_ = data_queue_.front().write_data_bits_data;
210	      *write_data_bits_strb_ = data_queue_.front().write_data_bits_strb;
211	      *write_data_bits_last_ = data_queue_.front().write_data_bits_last;
212	      if (*write_data_ready_) {
213	        data_queue_.pop();
214	      }
215	      clock().Eval();
216	    }
217	
218	    // Receive Response
219	    if (*write_resp_valid_) {
220	      assert(*write_resp_bits_resp_ == 0);
221	      auto it = outstanding_transactions_.find(*write_resp_bits_id_);
222	      if (it != outstanding_transactions_.end()) {
223	        *(it->second) = true;
224	        outstanding_transactions_.erase(it);
225	      }
226	    }
227	  }
228	
229	  // Signals
230	  // WAddr
231	  uint8_t* const write_addr_valid_;
232	  uint32_t* const write_addr_bits_addr_;
233	  uint8_t* const write_addr_bits_prot_;
234	  uint8_t* const write_addr_bits_id_;
235	  uint8_t* const write_addr_bits_len_;
236	  uint8_t* const write_addr_bits_size_;
237	  uint8_t* const write_addr_bits_burst_;
238	  uint8_t* const write_addr_bits_lock_;
239	  uint8_t* const write_addr_bits_cache_;
240	  uint8_t* const write_addr_bits_qos_;
241	  uint8_t* const write_addr_bits_region_;
242	  const uint8_t* const write_addr_ready_;
243	  // WData
244	  uint8_t* const write_data_valid_;
245	  VlWide<4>* const write_data_bits_data_;
246	  uint16_t* const write_data_bits_strb_;
247	  uint8_t* const write_data_bits_last_;
248	  const uint8_t* const write_data_ready_;
249	  // WResp
250	  const uint8_t* const write_resp_valid_;
251	  const uint8_t* const write_resp_bits_id_;
252	  const uint8_t* const write_resp_bits_resp_;
253	  uint8_t* const write_resp_ready_;
254	
255	  std::queue<AxiAddr> addr_queue_;
256	  std::queue<AxiWData> data_queue_;
257	  std::map<uint8_t /*id*/, std::shared_ptr<bool>> outstanding_transactions_;
258	};
