291	        read_addr_ready_(read_addr_ready),
292	        read_data_valid_(read_data_valid),
293	        read_data_bits_data(read_data_bits_data),
294	        read_data_bits_id_(read_data_bits_id),
295	        read_data_bits_resp_(read_data_bits_resp),
296	        read_data_bits_last_(read_data_bits_last),
297	        read_data_ready_(read_data_ready) {
298	    (*read_data_ready_) = 1;
299	  }
300	
301	  std::shared_ptr<Transaction> ReadTransaction(int id, uint32_t addr,
302	                                               uint32_t byte_length) {
303	    // Enqueue addr
304	    AxiAddr axi_addr = AxiAddr::FromIdAddrSize(id, addr, byte_length);
305	    addr_queue_.push(axi_addr);
306	
307	    // Enqueue data
308	    assert(outstanding_transactions_.find(id) ==
309	           outstanding_transactions_.end());
310	    const auto [it, success] =
311	        outstanding_transactions_.insert({id, std::make_shared<Transaction>()});
312	    it->second->finished = false;
313	    it->second->start_addr = addr;
314	    it->second->end_addr = addr + byte_length;
315	    it->second->data.reserve(byte_length);
316	    return it->second;
317	  }
318	
319	 private:
320	  void OnFallingEdge() final {
321	    // Send Addr
322	    *read_addr_valid_ = !addr_queue_.empty();
323	    clock().Eval();
324	    if (!addr_queue_.empty()) {
325	      *read_addr_bits_addr_ = addr_queue_.front().addr_bits_addr;
326	      *read_addr_bits_prot_ = addr_queue_.front().addr_bits_prot;
327	      *read_addr_bits_id_ = addr_queue_.front().addr_bits_id;
328	      *read_addr_bits_len_ = addr_queue_.front().addr_bits_len;
329	      *read_addr_bits_size_ = addr_queue_.front().addr_bits_size;
330	      *read_addr_bits_burst_ = addr_queue_.front().addr_bits_burst;
331	      *read_addr_bits_lock_ = addr_queue_.front().addr_bits_lock;
332	      *read_addr_bits_cache_ = addr_queue_.front().addr_bits_cache;
333	      *read_addr_bits_qos_ = addr_queue_.front().addr_bits_qos;
334	      *read_addr_bits_region_ = addr_queue_.front().addr_bits_region;
335	      if (*read_addr_ready_) {
336	        addr_queue_.pop();
337	      }
338	      clock().Eval();
339	    }
340	
341	    // Received data
342	    if (*read_data_valid_) {
343	      assert(*read_data_bits_resp_ == 0);
344	
345	      auto it = outstanding_transactions_.find(*read_data_bits_id_);
346	      if (it == outstanding_transactions_.end()) {
347	        return;
348	      }
349	
350	      // TODO(derekjchow): Should probably handle non-INCR mode.
351	      uint32_t sub_addr = it->second->start_addr % 16;
352	      uint32_t bytes_to_read = 16 - sub_addr;
353	      bytes_to_read = std::min(bytes_to_read,
354	                               it->second->end_addr - it->second->start_addr);
355	      const uint8_t* read_data =
356	          reinterpret_cast<const uint8_t*>(&(*read_data_bits_data)[0]);
357	      for (uint32_t i = 0; i < bytes_to_read; i++) {
358	        it->second->data.push_back(read_data[i + sub_addr]);
359	      }
360	      it->second->start_addr += bytes_to_read;
361	      if (*read_data_bits_last_) {
362	        it->second->finished = true;
363	        outstanding_transactions_.erase(it);
364	      }
365	    }
366	  }
367	
368	  // Signals
369	  // RAddr
370	  uint8_t* const read_addr_valid_;
371	  uint32_t* const read_addr_bits_addr_;
372	  uint8_t* const read_addr_bits_prot_;
373	  uint8_t* const read_addr_bits_id_;
374	  uint8_t* const read_addr_bits_len_;
375	  uint8_t* const read_addr_bits_size_;
376	  uint8_t* const read_addr_bits_burst_;
377	  uint8_t* const read_addr_bits_lock_;
378	  uint8_t* const read_addr_bits_cache_;
379	  uint8_t* const read_addr_bits_qos_;
380	  uint8_t* const read_addr_bits_region_;
381	  const uint8_t* const read_addr_ready_;
382	  // RData
383	  const uint8_t* const read_data_valid_;
384	  const VlWide<4>* const read_data_bits_data;
385	  const uint8_t* const read_data_bits_id_;
386	  const uint8_t* const read_data_bits_resp_;
387	  const uint8_t* const read_data_bits_last_;
388	  uint8_t* const read_data_ready_;
389	
390	  std::queue<AxiAddr> addr_queue_;
391	  std::map<uint8_t /*id*/, std::shared_ptr<Transaction>>
392	      outstanding_transactions_;
393	};
394	
395	// Struct representing the data transferred in an AXI4 read data channel.
396	struct AxiRData {
397	  VlWide<4> read_data_bits_data;
398	  uint8_t read_data_bits_id;
399	  uint8_t read_data_bits_resp;
400	  uint8_t read_data_bits_last;
401	};
