403	// A driver to control interactions of the read channels in an AXI4 master.
404	class AxiMasterReadDriver : Clock::Observer {
405	 public:
406	  AxiMasterReadDriver(
407	      Clock* clock, const uint8_t* read_addr_valid,
408	      const uint32_t* read_addr_bits_addr, const uint8_t* read_addr_bits_prot,
409	      const uint8_t* read_addr_bits_id, const uint8_t* read_addr_bits_len,
410	      const uint8_t* read_addr_bits_size, const uint8_t* read_addr_bits_burst,
411	      const uint8_t* read_addr_bits_lock, const uint8_t* read_addr_bits_cache,
412	      const uint8_t* read_addr_bits_qos, const uint8_t* read_addr_bits_region,
413	      uint8_t* read_addr_ready, uint8_t* read_data_valid,
414	      VlWide<4>* read_data_bits_data, uint8_t* read_data_bits_id,
415	      uint8_t* read_data_bits_resp, uint8_t* read_data_bits_last,
416	      const uint8_t* read_data_ready)
417	      : Clock::Observer(clock),
418	        read_addr_valid_(read_addr_valid),
419	        read_addr_bits_addr_(read_addr_bits_addr),
420	        read_addr_bits_prot_(read_addr_bits_prot),
421	        read_addr_bits_id_(read_addr_bits_id),
422	        read_addr_bits_len_(read_addr_bits_len),
423	        read_addr_bits_size_(read_addr_bits_size),
424	        read_addr_bits_burst_(read_addr_bits_burst),
425	        read_addr_bits_lock_(read_addr_bits_lock),
426	        read_addr_bits_cache_(read_addr_bits_cache),
427	        read_addr_bits_qos_(read_addr_bits_qos),
428	        read_addr_bits_region_(read_addr_bits_region),
429	        read_addr_ready_(read_addr_ready),
430	        read_data_valid_(read_data_valid),
431	        read_data_bits_data_(read_data_bits_data),
432	        read_data_bits_id_(read_data_bits_id),
433	        read_data_bits_resp_(read_data_bits_resp),
434	        read_data_bits_last_(read_data_bits_last),
435	        read_data_ready_(read_data_ready) {
436	    (*read_addr_ready_) = 1;
437	  }
438	
439	  void RegisterReadCallback(
440	      std::function<AxiRData(const AxiAddr& addr)> read_cb) {
441	    read_cb_ = read_cb;
442	  }
443	
444	 private:
445	  void OnFallingEdge() final {
446	    // Send Data
447	    *read_data_valid_ = !data_queue_.empty();
448	    clock().Eval();
449	    if (!data_queue_.empty()) {
450	      *read_data_bits_data_ = data_queue_.front().read_data_bits_data;
451	      *read_data_bits_id_ = data_queue_.front().read_data_bits_id;
452	      *read_data_bits_resp_ = data_queue_.front().read_data_bits_resp;
453	      *read_data_bits_last_ = data_queue_.front().read_data_bits_last;
454	      if (*read_data_ready_) {
455	        data_queue_.pop();
456	      }
457	      clock().Eval();
458	    }
459	
460	    // Receive Address
461	    if (*read_addr_valid_) {
462	      axi_addr_.addr_bits_addr = *read_addr_bits_addr_;
463	      axi_addr_.addr_bits_prot = *read_addr_bits_prot_;
464	      axi_addr_.addr_bits_id = *read_addr_bits_id_;
465	      axi_addr_.addr_bits_len = *read_addr_bits_len_;
466	      axi_addr_.addr_bits_size = *read_addr_bits_size_;
467	      axi_addr_.addr_bits_burst = *read_addr_bits_burst_;
468	      axi_addr_.addr_bits_lock = *read_addr_bits_lock_;
469	      axi_addr_.addr_bits_cache = *read_addr_bits_cache_;
470	      axi_addr_.addr_bits_qos = *read_addr_bits_qos_;
471	      axi_addr_.addr_bits_region = *read_addr_bits_region_;
472	
473	      if (read_cb_) {
474	        AxiRData read_result = read_cb_(axi_addr_);
475	        data_queue_.push(read_result);
476	      } else {
477	        assert(false && "Read callback is empty!");
478	      }
479	    }
480	  }
481	
482	  // Signals
483	  // RAddr
484	  const uint8_t* const read_addr_valid_;
485	  const uint32_t* const read_addr_bits_addr_;
486	  const uint8_t* const read_addr_bits_prot_;
487	  const uint8_t* const read_addr_bits_id_;
488	  const uint8_t* const read_addr_bits_len_;
489	  const uint8_t* const read_addr_bits_size_;
490	  const uint8_t* const read_addr_bits_burst_;
491	  const uint8_t* const read_addr_bits_lock_;
492	  const uint8_t* const read_addr_bits_cache_;
493	  const uint8_t* const read_addr_bits_qos_;
494	  const uint8_t* const read_addr_bits_region_;
495	  uint8_t* const read_addr_ready_;
496	  // RData
497	  uint8_t* const read_data_valid_;
498	  VlWide<4>* const read_data_bits_data_;
499	  uint8_t* const read_data_bits_id_;
500	  uint8_t* const read_data_bits_resp_;
501	  uint8_t* const read_data_bits_last_;
502	  const uint8_t* const read_data_ready_;
503	
504	  std::queue<AxiRData> data_queue_;
505	  AxiAddr axi_addr_;
506	  std::function<AxiRData(const AxiAddr&)> read_cb_;
507	};
508	
509	// Struct representing the data transferred in an AXI4 read data channel.
510	struct AxiWResp {
511	  uint8_t write_resp_bits_id;
512	  uint8_t write_resp_bits_resp;
513	};
514	
515	// A driver to control interactions of the write channels in an AXI4 slave.
516	class AxiMasterWriteDriver : Clock::Observer {
517	 public:
518	  AxiMasterWriteDriver(
519	      Clock* clock, const uint8_t* write_addr_valid,
520	      const uint32_t* write_addr_bits_addr, const uint8_t* write_addr_bits_prot,
521	      const uint8_t* write_addr_bits_id, const uint8_t* write_addr_bits_len,
522	      const uint8_t* write_addr_bits_size, const uint8_t* write_addr_bits_burst,
523	      const uint8_t* write_addr_bits_lock, const uint8_t* write_addr_bits_cache,
524	      const uint8_t* write_addr_bits_qos, const uint8_t* write_addr_bits_region,
525	      uint8_t* write_addr_ready, const uint8_t* write_data_valid,
526	      const VlWide<4>* write_data_bits_data,
527	      const uint16_t* write_data_bits_strb, const uint8_t* write_data_bits_last,
528	      uint8_t* write_data_ready, uint8_t* write_resp_valid,
529	      uint8_t* write_resp_bits_id, uint8_t* write_resp_bits_resp,
530	      const uint8_t* write_resp_ready)
531	      : Clock::Observer(clock),
532	        write_addr_valid_(write_addr_valid),
533	        write_addr_bits_addr_(write_addr_bits_addr),
534	        write_addr_bits_prot_(write_addr_bits_prot),
535	        write_addr_bits_id_(write_addr_bits_id),
536	        write_addr_bits_len_(write_addr_bits_len),
537	        write_addr_bits_size_(write_addr_bits_size),
538	        write_addr_bits_burst_(write_addr_bits_burst),
539	        write_addr_bits_lock_(write_addr_bits_lock),
540	        write_addr_bits_cache_(write_addr_bits_cache),
541	        write_addr_bits_qos_(write_addr_bits_qos),
542	        write_addr_bits_region_(write_addr_bits_region),
543	        write_addr_ready_(write_addr_ready),
544	        write_data_valid_(write_data_valid),
545	        write_data_bits_data_(write_data_bits_data),
546	        write_data_bits_strb_(write_data_bits_strb),
547	        write_data_bits_last_(write_data_bits_last),
548	        write_data_ready_(write_data_ready),
549	        write_resp_valid_(write_resp_valid),
550	        write_resp_bits_id_(write_resp_bits_id),
551	        write_resp_bits_resp_(write_resp_bits_resp),
552	        write_resp_ready_(write_resp_ready) {
553	    *write_addr_ready_ = 0;
554	    *write_data_ready_ = 0;
555	  }
556	  ~AxiMasterWriteDriver() final = default;
557	
558	  void RegisterWriteCallback(
559	      std::function<AxiWResp(const AxiAddr& addr, const AxiWData& data)>
560	          write_cb) {
561	    write_cb_ = write_cb;
562	  }
563	
564	 private:
565	  void OnFallingEdge() final {
566	    // Send Response
567	    *write_resp_valid_ = !resp_queue_.empty();
568	    clock().Eval();
569	    if (!resp_queue_.empty()) {
570	      *write_resp_bits_id_ = resp_queue_.front().write_resp_bits_id;
571	      *write_resp_bits_resp_ = resp_queue_.front().write_resp_bits_resp;
572	      if (*write_resp_ready_) {
573	        resp_queue_.pop();
574	      }
575	      clock().Eval();
576	    }
577	
578	    // Receive Addr
579	    if (*write_addr_valid_) {
580	      axi_addr_.addr_bits_addr = *write_addr_bits_addr_;
581	      axi_addr_.addr_bits_prot = *write_addr_bits_prot_;
582	      axi_addr_.addr_bits_id = *write_addr_bits_id_;
583	      axi_addr_.addr_bits_len = *write_addr_bits_len_;
584	      axi_addr_.addr_bits_size = *write_addr_bits_size_;
585	      axi_addr_.addr_bits_burst = *write_addr_bits_burst_;
586	      axi_addr_.addr_bits_lock = *write_addr_bits_lock_;
587	      axi_addr_.addr_bits_cache = *write_addr_bits_cache_;
588	      axi_addr_.addr_bits_qos = *write_addr_bits_qos_;
589	      axi_addr_.addr_bits_region = *write_addr_bits_region_;
590	    }
591	    // Receive Data
592	    if (*write_data_valid_) {
593	      axi_data_.write_data_bits_data = *write_data_bits_data_;
594	      axi_data_.write_data_bits_strb = *write_data_bits_strb_;
595	      axi_data_.write_data_bits_last = *write_data_bits_last_;
596	    }
597	
598	    if (*write_addr_valid_ && *write_data_valid_) {
599	      *write_addr_ready_ = 1;
600	      *write_data_ready_ = 1;
601	      if (write_cb_) {
602	        AxiWResp resp_result = write_cb_(axi_addr_, axi_data_);
603	        resp_queue_.push(resp_result);
604	      } else {
605	        assert(false && "Write callback is empty!");
606	      }
607	    } else {
608	      *write_addr_ready_ = 0;
609	      *write_data_ready_ = 0;
610	    }
611	  }
612	
613	  // Signals
614	  // WAddr
615	  const uint8_t* const write_addr_valid_;
616	  const uint32_t* const write_addr_bits_addr_;
617	  const uint8_t* const write_addr_bits_prot_;
618	  const uint8_t* const write_addr_bits_id_;
619	  const uint8_t* const write_addr_bits_len_;
620	  const uint8_t* const write_addr_bits_size_;
621	  const uint8_t* const write_addr_bits_burst_;
622	  const uint8_t* const write_addr_bits_lock_;
623	  const uint8_t* const write_addr_bits_cache_;
624	  const uint8_t* const write_addr_bits_qos_;
625	  const uint8_t* const write_addr_bits_region_;
626	  uint8_t* const write_addr_ready_;
627	  // WData
628	  const uint8_t* const write_data_valid_;
629	  const VlWide<4>* const write_data_bits_data_;
630	  const uint16_t* const write_data_bits_strb_;
631	  const uint8_t* const write_data_bits_last_;
632	  uint8_t* const write_data_ready_;
633	  // WResp
634	  uint8_t* const write_resp_valid_;
635	  uint8_t* const write_resp_bits_id_;
636	  uint8_t* const write_resp_bits_resp_;
