316	absl::Status CoreMiniAxi_tb::LoadElfAsync(const std::string& file_name) {
317	  absl::MutexLock lock(&transfer_queue_mtx_);
318	  int fd = open(file_name.c_str(), 0);
319	  CHECK(fd > 0);
320	  struct stat sb;
321	  CHECK(fstat(fd, &sb) == 0);
322	  auto file_size = sb.st_size;
323	  auto file_data = mmap(nullptr, file_size, PROT_READ, MAP_PRIVATE, fd, 0);
324	  CHECK(file_data != MAP_FAILED);
325	  close(fd);
326	
327	  uint32_t elf_magic = 0x464c457f;
328	  uint8_t* data8 = reinterpret_cast<uint8_t*>(file_data);
329	  if (memcmp(file_data, &elf_magic, sizeof(elf_magic)) == 0) {
330	    std::vector<DataTransfer> elf_transfers;
331	    const Elf32_Ehdr* elf_header = reinterpret_cast<Elf32_Ehdr*>(file_data);
332	    auto entry_point = elf_header->e_entry;
333	    // Reserve space for write+read+expect for each section, and one additional
334	    // for the entry point CSR.
335	    elf_transfers.reserve(3 * elf_header->e_phnum + 1);
336	    ::LoadElf(data8,
337	              [this, &elf_transfers](void* dest, const void* src, size_t count) {
338	                uint64_t addr = reinterpret_cast<uint64_t>(dest);
339	                uint32_t itcm_size = KP_itcmSizeKBytes * 1024;
340	                uint32_t dtcm_size = KP_dtcmSizeKBytes * 1024;
341	                uint32_t dtcm_base = (KP_itcmSizeKBytes == 8 && KP_dtcmSizeKBytes == 32) ? 0x10000 : 0x100000;
342	                bool in_tcm = (addr < itcm_size) || (addr >= dtcm_base && addr < dtcm_base + dtcm_size);
343	
344	                bool use_backdoor = this->backdoor_load_;
345	                if (use_backdoor && in_tcm) {
346	                  this->BackdoorLoad(addr, reinterpret_cast<const uint8_t*>(src), count);
347	                } else {
348	                  elf_transfers.push_back(utils::Write(
349	                      reinterpret_cast<uint64_t>(dest),
350	                      reinterpret_cast<uint8_t*>(const_cast<void*>(src)), count));
351	                  elf_transfers.push_back(
352	                      utils::Read(reinterpret_cast<uint64_t>(dest), count));
353	                  elf_transfers.push_back(utils::Expect(
354	                      reinterpret_cast<uint8_t*>(const_cast<void*>(src)), count));
355	                }
356	                return dest;
357	              });
358	    elf_transfers.push_back(utils::Write(
359	      csr_addr_ + 0x4, reinterpret_cast<uint8_t*>(&entry_point), sizeof(entry_point)
360	    ));
361	    transfer_queue_.push(
362	        std::make_unique<TrafficDesc>(utils::merge(elf_transfers)));
363	    uint32_t tohost;
364	    if (::LookupSymbol(data8, "tohost", &tohost)) {
365	      // NB: This alignment requirement is to simplify the watchpoint implementation.
366	      CHECK((tohost & 0xFFFFFFF0L) == tohost);
367	      tohost_addr_ = tohost;
368	    }
369	    uint32_t tohost_ready;
370	    if (::LookupSymbol(data8, "tohost_ready", &tohost_ready)) {
371	      tohost_ready_addr_ = tohost_ready;
372	    }
373	    uint32_t fromhost;
374	    if (::LookupSymbol(data8, "fromhost", &fromhost)) {
375	      fromhost_addr_ = fromhost;
376	    }
377	    uint32_t fromhost_ready;
378	    if (::LookupSymbol(data8, "fromhost_ready", &fromhost_ready)) {
379	      fromhost_ready_addr_ = fromhost_ready;
380	    }
381	  } else {
382	    // Transaction to fill ITCM with the provided binary.
383	    transfer_queue_.push(
384	        std::make_unique<TrafficDesc>(utils::merge(std::vector<DataTransfer>(
385	            {utils::Write(0, data8, file_size), utils::Read(0, file_size),
386	             utils::Expect(data8, file_size)}))));
387	  }
388	  munmap(file_data, file_size);
389	  return absl::OkStatus();
390	}
