445	void CoreMiniAxi_tb::TraceInstructions() {
446	#define TRACE_INSTRUCTION(x) do { \
447	  uint32_t pc, inst, idx; \
448	  pc = debug_io_.rb_inst_##x##_bits_pc.read().get_word(0); \
449	  inst = debug_io_.rb_inst_##x##_bits_inst.read().get_word(0); \
450	  idx = debug_io_.rb_inst_##x##_bits_idx.read().get_word(0); \
451	  bool trap = debug_io_.rb_inst_##x##_bits_trap.read(); \
452	  if (debug_io_.rb_inst_##x##_valid.read()) { \
453	    auto data = debug_io_.rb_inst_##x##_bits_data.read(); \
454	    std::vector<uint8_t> data_vec(data.length() / 8); \
455	    int num_words = data.length() / 32; \
456	    for (int i = 0; i < num_words; ++i) { \
457	      uint32_t word = data.get_word((num_words - 1) - i); \
458	      data_vec[i*4+0] = (word >> 24) & 0xff; \
459	      data_vec[i*4+1] = (word >> 16) & 0xff; \
460	      data_vec[i*4+2] = (word >> 8) & 0xff; \
461	      data_vec[i*4+3] = word & 0xff; \
462	    } \
463	    tracer_.TraceInstructionRaw(pc, inst, idx, data_vec, trap); \
464	  } \
465	} while (0);
466	REPEAT(TRACE_INSTRUCTION, KP_retirementBufferSize);
467	#undef TRACE_INSTRUCTION
468	}
