470	void CoreMiniAxi_tb::tohost_reader_thread() {
471	  while (true) {
472	    wait(tohost_read_event_);
473	    uint64_t addr = tohost_read_addr_;
474	
475	    tlm::tlm_generic_payload trans;
476	    sc_time delay = SC_ZERO_TIME;
477	
478	    if (addr == 0 && tohost_addr_.has_value()) {
479	      // Triggered by tohost_ready. Read the actual payload from tohost.
480	      uint64_t tohost_payload = 0;
481	      trans.set_command(tlm::TLM_READ_COMMAND);
482	      trans.set_address(tohost_addr_.value());
483	      trans.set_data_ptr(reinterpret_cast<uint8_t*>(&tohost_payload));
484	      trans.set_data_length(8);
485	      trans.set_streaming_width(8);
486	      trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
487	      delay = SC_ZERO_TIME;
488	      tohost_initiator_socket_->b_transport(trans, delay);
489	
490	      if (tohost_payload & 1) {
491	        tohost_halt = true;
492	        tohost_val = static_cast<uint32_t>(tohost_payload);
493	        continue;
494	      }
495	      addr = tohost_payload;
496	    }
497	
498	    if (addr == 0) continue;
499	
500	    uint8_t data[64];
501	
502	    trans.set_command(tlm::TLM_READ_COMMAND);
503	    trans.set_address(addr);
504	    trans.set_data_ptr(data);
505	    trans.set_data_length(64);
506	    trans.set_streaming_width(64);
507	    trans.set_byte_enable_ptr(nullptr);
508	    trans.set_dmi_allowed(false);
509	    trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
510	
511	    tohost_initiator_socket_->b_transport(trans, delay);
512	
513	    uint64_t resp_val = 0;
514	    if (trans.is_response_error()) {
515	      LOG(ERROR) << "tohost read error at " << std::hex << addr << ": " << trans.get_response_string();
516	    } else {
517	      // Clear tohost to acknowledge receipt of the address.
518	      if (tohost_addr_.has_value()) {
519	        uint64_t zero64 = 0;
520	        trans.set_command(tlm::TLM_WRITE_COMMAND);
521	        trans.set_address(tohost_addr_.value());
522	        trans.set_data_ptr(reinterpret_cast<uint8_t*>(&zero64));
523	        trans.set_data_length(8);
524	        trans.set_streaming_width(8);
525	        trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
526	        delay = SC_ZERO_TIME;
527	        tohost_initiator_socket_->b_transport(trans, delay);
528	      }
529	
530	      uint64_t words[8];
531	      memcpy(words, data, sizeof(words));
532	      switch (words[0]) {
533	        case 56:  // sys_openat
534	        {
535	          int64_t dirfd_guest = static_cast<int64_t>(words[1]);
536	          int dirfd = (dirfd_guest == -100) ? AT_FDCWD : static_cast<int>(dirfd_guest);
537	          auto iter = fd_map_.find(words[1]);
538	          if (iter != fd_map_.end()) {
539	            dirfd = iter->second;
540	          }
541	          uint64_t name_addr = words[2];
542	          size_t name_len = static_cast<size_t>(words[3]);
543	          int flags = static_cast<int>(words[4]);
544	          int mode = static_cast<int>(words[5]);
545	
546	          std::vector<char> name(name_len + 1, 0);
547	          trans.set_command(tlm::TLM_READ_COMMAND);
548	          trans.set_address(name_addr);
549	          trans.set_data_ptr(reinterpret_cast<uint8_t*>(name.data()));
550	          trans.set_data_length(name_len);
551	          trans.set_streaming_width(name_len);
552	          trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
553	          delay = SC_ZERO_TIME;
554	          tohost_initiator_socket_->b_transport(trans, delay);
555	          if (trans.is_response_error()) {
556	            resp_val = -1;
557	          } else {
558	            int host_flags = 0;
559	            if (flags & 0x0001) host_flags |= O_WRONLY;
560	            if (flags & 0x0002) host_flags |= O_RDWR;
561	            if (flags & 0x0200) host_flags |= O_CREAT;
562	            if (flags & 0x0400) host_flags |= O_TRUNC;
563	            if (flags & 0x0800) host_flags |= O_EXCL;
564	            if (flags & 0x4000) host_flags |= O_APPEND;
565	
566	            int host_fd = openat(dirfd, name.data(), host_flags, mode);
567	            if (host_fd >= 0) {
568	              resp_val = host_fd + 3; // Offset to avoid overlapping with stdio
569	              fd_map_[resp_val] = host_fd;
570	            } else {
571	              resp_val = -1;
572	            }
573	          }
574	        } break;
575	
576	        case 57:  // sys_close
577	        {
578	          uint64_t guest_fd = words[1];
579	          auto iter = fd_map_.find(guest_fd);
580	          if (iter != fd_map_.end()) {
581	            resp_val = close(iter->second);
582	            fd_map_.erase(iter);
583	          } else {
584	            resp_val = -1;
585	          }
586	        } break;
587	
588	        case 62:  // sys_lseek
589	        {
590	          uint64_t guest_fd = words[1];
591	          auto iter = fd_map_.find(guest_fd);
592	          int host_fd = (iter == fd_map_.end()) ? -1 : iter->second;
593	          off_t offset = static_cast<off_t>(words[2]);
594	          int whence = static_cast<int>(words[3]);
595	          resp_val = lseek(host_fd, offset, whence);
596	        } break;
597	
598	        case 63:  // sys_read
599	        {
600	          uint64_t guest_fd = words[1];
601	          uint64_t buf_addr = words[2];
602	          size_t buf_len = static_cast<size_t>(words[3]);
603	          std::vector<uint8_t> buf(buf_len);
604	          ssize_t bytes_read;
605	          if (guest_fd == 0) {
606	            bytes_read = read(0, buf.data(), buf_len);
607	          } else {
608	            auto iter = fd_map_.find(guest_fd);
609	            int host_fd = (iter == fd_map_.end()) ? -1 : iter->second;
610	            bytes_read = read(host_fd, buf.data(), buf_len);
611	          }
612	
613	          if (bytes_read > 0) {
614	            trans.set_command(tlm::TLM_WRITE_COMMAND);
615	            trans.set_address(buf_addr);
616	            trans.set_data_ptr(buf.data());
617	            trans.set_data_length(bytes_read);
618	            trans.set_streaming_width(bytes_read);
619	            trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
620	            delay = SC_ZERO_TIME;
621	            tohost_initiator_socket_->b_transport(trans, delay);
622	            if (trans.is_response_error()) {
623	              LOG(ERROR) << "sys_read buf write error at " << std::hex << buf_addr;
624	              resp_val = -1;
625	            } else {
626	              resp_val = bytes_read;
627	            }
628	          } else {
629	            resp_val = bytes_read;
630	          }
631	        } break;
632	
633	        case 64:  // sys_write
634	        {
635	          uint64_t guest_fd = words[1];
636	          uint64_t buf_addr = words[2];
637	          size_t buf_len = static_cast<size_t>(words[3]);
638	          std::vector<uint8_t> buf(buf_len);
639	          trans.set_command(tlm::TLM_READ_COMMAND);
640	          trans.set_address(buf_addr);
641	          trans.set_data_ptr(buf.data());
642	          trans.set_data_length(buf_len);
643	          trans.set_streaming_width(buf_len);
644	          trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
645	          delay = SC_ZERO_TIME;
646	          tohost_initiator_socket_->b_transport(trans, delay);
647	          if (trans.is_response_error()) {
648	            LOG(ERROR) << "sys_write buf read error at " << std::hex << buf_addr;
649	            resp_val = -1;
650	          } else {
651	            if (guest_fd == 1 || guest_fd == 2) {
652	              std::string s(reinterpret_cast<char*>(buf.data()), buf_len);
653	              std::cout << s << std::flush;
654	              resp_val = buf_len;
655	            } else {
656	              auto iter = fd_map_.find(guest_fd);
657	              int host_fd = (iter == fd_map_.end()) ? -1 : iter->second;
658	              resp_val = write(host_fd, buf.data(), buf_len);
659	            }
660	          }
661	        } break;
662	
663	        case 67:  // sys_pread
664	        {
665	          uint64_t guest_fd = words[1];
666	          auto iter = fd_map_.find(guest_fd);
667	          int host_fd = (iter == fd_map_.end()) ? -1 : iter->second;
668	          uint64_t buf_addr = words[2];
669	          size_t buf_len = static_cast<size_t>(words[3]);
670	          off_t offset = static_cast<off_t>(words[4]);
671	          std::vector<uint8_t> buf(buf_len);
672	          ssize_t bytes_read = pread(host_fd, buf.data(), buf_len, offset);
673	          if (bytes_read > 0) {
674	            trans.set_command(tlm::TLM_WRITE_COMMAND);
675	            trans.set_address(buf_addr);
676	            trans.set_data_ptr(buf.data());
677	            trans.set_data_length(bytes_read);
678	            trans.set_streaming_width(bytes_read);
679	            trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
680	            delay = SC_ZERO_TIME;
681	            tohost_initiator_socket_->b_transport(trans, delay);
682	            if (trans.is_response_error()) {
683	              LOG(ERROR) << "sys_pread buf write error at " << std::hex << buf_addr;
684	              resp_val = -1;
685	            } else {
686	              resp_val = bytes_read;
687	            }
688	          } else {
689	            resp_val = bytes_read;
690	          }
691	        } break;
692	
693	        case 68:  // sys_pwrite
694	        {
695	          uint64_t guest_fd = words[1];
696	          auto iter = fd_map_.find(guest_fd);
697	          int host_fd = (iter == fd_map_.end()) ? -1 : iter->second;
698	          uint64_t buf_addr = words[2];
699	          size_t buf_len = static_cast<size_t>(words[3]);
700	          off_t offset = static_cast<off_t>(words[4]);
701	          std::vector<uint8_t> buf(buf_len);
702	          trans.set_command(tlm::TLM_READ_COMMAND);
703	          trans.set_address(buf_addr);
704	          trans.set_data_ptr(buf.data());
705	          trans.set_data_length(buf_len);
706	          trans.set_streaming_width(buf_len);
707	          trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
708	          delay = SC_ZERO_TIME;
709	          tohost_initiator_socket_->b_transport(trans, delay);
710	          if (trans.is_response_error()) {
711	            LOG(ERROR) << "sys_pwrite buf read error at " << std::hex << buf_addr;
712	            resp_val = -1;
713	          } else {
714	            resp_val = pwrite(host_fd, buf.data(), buf_len, offset);
715	          }
716	        } break;
717	
718	        case 93:  // sys_exit
719	          tohost_halt = true;
720	          tohost_val = words[1];
721	          break;
722	
723	        case 2011:  // sys_getmainvars
724	        {
725	          uint64_t buf_addr = words[1];
726	          uint64_t limit = words[2];
727	          uint64_t argc = 1;
728	          const char* arg0 = "coralnpu.elf";
729	          uint64_t arg0_addr = buf_addr + 16; // Place string after argc and argv[0] pointer
730	          std::vector<uint64_t> packet(2);
731	          packet[0] = argc;
732	          packet[1] = arg0_addr;
733	          if (limit >= (16 + strlen(arg0) + 1)) {
734	            // Write argc and argv pointers
735	            trans.set_command(tlm::TLM_WRITE_COMMAND);
736	            trans.set_address(buf_addr);
737	            trans.set_data_ptr(reinterpret_cast<uint8_t*>(packet.data()));
738	            trans.set_data_length(16);
739	            trans.set_streaming_width(16);
740	            trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
741	            delay = SC_ZERO_TIME;
742	            tohost_initiator_socket_->b_transport(trans, delay);
743	
744	            // Write the string
745	            trans.set_command(tlm::TLM_WRITE_COMMAND);
746	            trans.set_address(arg0_addr);
747	            trans.set_data_ptr(reinterpret_cast<uint8_t*>(const_cast<char*>(arg0)));
748	            trans.set_data_length(strlen(arg0) + 1);
749	            trans.set_streaming_width(strlen(arg0) + 1);
750	            trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
751	            tohost_initiator_socket_->b_transport(trans, delay);
752	
753	            resp_val = 0; // Success
754	          } else {
755	            resp_val = -1;
756	          }
757	        } break;
758	
759	        default:
760	          resp_val = -1;
761	          break;
762	      }
763	    }
764	
765	    // Write return code back to the first word of the packet.
766	    // Use 32-bit writes to be safe with the 32-bit core's bus.
767	    uint32_t resp_low = static_cast<uint32_t>(resp_val);
768	    uint32_t resp_high = static_cast<uint32_t>(resp_val >> 32);
769	
770	    trans.set_command(tlm::TLM_WRITE_COMMAND);
771	    trans.set_address(addr);
772	    trans.set_data_ptr(reinterpret_cast<uint8_t*>(&resp_low));
773	    trans.set_data_length(4);
774	    trans.set_streaming_width(4);
775	    trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
776	    delay = SC_ZERO_TIME;
777	    tohost_initiator_socket_->b_transport(trans, delay);
778	
779	    trans.set_address(addr + 4);
780	    trans.set_data_ptr(reinterpret_cast<uint8_t*>(&resp_high));
781	    tohost_initiator_socket_->b_transport(trans, delay);
782	
783	    // Write completion response to fromhost.
784	    if (fromhost_addr_.has_value()) {
785	      // libgloss-htif htif_syscall polls for fromhost != 0.
786	      // After it sees != 0, it clears fromhost.
787	      uint32_t resp_low = 1;
788	      uint32_t resp_high = 0;
789	
790	      trans.set_command(tlm::TLM_WRITE_COMMAND);
791	      trans.set_address(fromhost_addr_.value());
792	      trans.set_data_ptr(reinterpret_cast<uint8_t*>(&resp_low));
793	      trans.set_data_length(4);
794	      trans.set_streaming_width(4);
795	      trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
796	      delay = SC_ZERO_TIME;
797	      tohost_initiator_socket_->b_transport(trans, delay);
798	
799	      trans.set_address(fromhost_addr_.value() + 4);
800	      trans.set_data_ptr(reinterpret_cast<uint8_t*>(&resp_high));
801	      tohost_initiator_socket_->b_transport(trans, delay);
802	    }
803	
804	    if (fromhost_ready_addr_.has_value()) {
805	      uint64_t one64 = 1;
806	      trans.set_command(tlm::TLM_WRITE_COMMAND);
807	      trans.set_address(fromhost_ready_addr_.value());
808	      trans.set_data_ptr(reinterpret_cast<uint8_t*>(&one64));
809	      trans.set_data_length(8);
810	      trans.set_streaming_width(8);
811	      trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
812	      delay = SC_ZERO_TIME;
813	      tohost_initiator_socket_->b_transport(trans, delay);
814	    }
815	
816	    // Clear tohost_ready if present.
817	    if (tohost_ready_addr_.has_value()) {
818	      uint64_t zero64 = 0;
819	      trans.set_command(tlm::TLM_WRITE_COMMAND);
820	      trans.set_address(tohost_ready_addr_.value());
821	      trans.set_data_ptr(reinterpret_cast<uint8_t*>(&zero64));
822	      trans.set_data_length(8);
823	      trans.set_streaming_width(8);
824	      trans.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
825	      delay = SC_ZERO_TIME;
826	      tohost_initiator_socket_->b_transport(trans, delay);
827	    }
828	  }
829	}
