831	void CoreMiniAxi_tb::posedge() {
832	  const bool core_io_dbus_valid = debug_io_.dbus_valid;
833	  const bool core_io_dbus_write = debug_io_.dbus_bits_write;
834	  const uint32_t core_io_dbus_addr = debug_io_.dbus_bits_addr.read().get_word(0);
835	
836	  // If we have tohost_ready, trigger only when it's written with 1.
837	  if (tohost_ready_addr_.has_value() && core_io_dbus_valid && core_io_dbus_write && (core_io_dbus_addr == tohost_ready_addr_.value())) {
838	    const uint32_t wdata0 = debug_io_.dbus_bits_wdata.read().get_word(0);
839	    if (wdata0 != 1) return;
840	
841	    // We trigger the read event, which will read from 'tohost' symbol address.
842	    // The tohost_reader_thread already uses tohost_read_addr_ which we should update here.
843	    // Wait, the tohost_reader_thread uses tohost_read_addr_ set in posedge.
844	    // We need to READ the current value of tohost from memory.
845	    // But posedge() shouldn't do bus transactions.
846	    // Let's modify tohost_reader_thread to read tohost if it's not provided.
847	    tohost_read_addr_ = 0; // Signal to thread to read 'tohost' from its known address
848	    tohost_read_event_.notify();
849	    return;
850	  }
851	
852	  // Fallback/Legacy support: trigger on tohost write if tohost_ready is not present.
853	  if (!tohost_ready_addr_.has_value() && tohost_addr_.has_value() && core_io_dbus_valid && core_io_dbus_write && (core_io_dbus_addr == tohost_addr_.value())) {
854	    const uint32_t wdata0 = debug_io_.dbus_bits_wdata.read().get_word(0);
855	    if (wdata0 == 0) return;
856	    if (wdata0 & 1) {
857	      tohost_halt = true;
858	      tohost_val = wdata0;
859	    } else {
860	      tohost_read_addr_ = wdata0;
861	      tohost_read_event_.notify();
862	    }
863	  }
864	
865	  if (instr_trace_) {
866	    TraceInstructions();
867	  }
868	
869	  static bool invoked_halted_cb = false;
870	  if ((io_halted || io_fault || tohost_halt) && !invoked_halted_cb) {
871	    // If instruction tracing is enabled,
872	    // print the data about the instruction trace.
873	    if (instr_trace_) {
874	      tracer_.PrintTrace();
875	    }
876	    invoked_halted_cb = true;
877	    if (halted_cb_) {
878	      halted_cb_.value()();
879	    }
880	  }
881	
882	  static bool wfi_seen = false;
883	  if (io_wfi && !wfi_seen) {
884	    io_irq = true;
885	    wfi_seen = true;
886	    if (wfi_cb_) {
887	      wfi_cb_.value()();
888	    }
889	  } else if (!io_wfi && wfi_seen) {
890	    io_irq = false;
891	    wfi_seen = false;
892	  } else {
893	    io_irq = false;
894	  }
895	
896	
897	  if (!transfer_in_progress_) {
898	    absl::MutexLock lock(&transfer_queue_mtx_);
899	    if (!transfer_queue_.empty()) {
900	      ITrafficDesc* transfer = transfer_queue_.front().get();
901	      tg_.addTransfers(transfer, 0, CoreMiniAxi_tb::axi_transaction_done_cb);
902	      transfer_in_progress_ = true;
903	    }
904	  }
905	}
